```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract ClosedPresaleMint {
    address private immutable owner;
    uint256 public price;
    uint256 public totalSupply;
    uint256 public maxSupply;
    mapping(address => bool) public claimedWhitelistStatus;
    enum State { CLOSED, PRESALE, PUBLIC }
    State public currentState = State.CLOSED;

    event PresaleStarted();
    event PublicSaleStarted();
    event Minted(address indexed to, uint256 amount);

    bool private locked;

    modifier noReentrancy() {
        require(!locked, "No reentrancy");
        locked = true;
        _;
        locked = false;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    constructor(uint256 price_, uint256 maxSupply_) {
        owner = msg.sender;
        price = price_;
        maxSupply = maxSupply_;
    }

    function startPresale() public onlyOwner {
        require(currentState == State.CLOSED, "Presale already started or ongoing sale");
        currentState = State.PRESALE;
        emit PresaleStarted();
    }

    function startPublicSale() public onlyOwner {
        require(currentState == State.PRESALE, "Public sale already started or presale not started");
        currentState = State.PUBLIC;
        emit PublicSaleStarted();
    }

    function mintNFT() public payable noReentrancy {
        require(currentState == State.PRESALE, "Presale not active");
        require(!claimedWhitelistStatus[msg.sender], "Already claimed whitelist spot");
        require(msg.value >= price, "Insufficient funds");
        require(totalSupply + 1 <= maxSupply, "Max supply reached");

        claimedWhitelistStatus[msg.sender] = true;
        totalSupply += 1;
        emit Minted(msg.sender, 1);
    }

    function mintPublicNFT(uint256 amount) public payable noReentrancy {
        require(currentState == State.PUBLIC, "Public sale not active");
        require(amount > 0, "Amount must be greater than zero");
        require(msg.value >= amount * price, "Insufficient funds");
        require(totalSupply + amount <= maxSupply, "Max supply reached");

        totalSupply += amount;
        emit Minted(msg.sender, amount);
    }

    function getPrice() public view returns (uint256) {
        return price;
    }

    function getMaxSupply() public view returns (uint256) {
        return maxSupply;
    }

    function getClaimedWhitelistStatus(address user) public view returns (bool) {
        return claimedWhitelistStatus[user];
    }
}
