// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract ClosedPresaleMint {
    address private immutable owner;
    uint256 public price;
    uint256 public totalSupply;
    uint256 public maxSupply;
    mapping(address => bool) public claimedWhitelistStatus;
    enum State { CLOSED, PRESALE, PUBLIC }
    State public currentState = State.CLOSED;

    event PresaleStarted();
    event PublicSaleStarted();
    event Minted(address indexed to, uint256 amount);

    bool private locked;

    modifier noReentrancy() {
        require(!locked, "No reentrancy");
        locked = true;
        _;
        locked = false;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    constructor(uint256 _price, uint256 _maxSupply) {
        owner = msg.sender;
        price = _price;
        maxSupply = _maxSupply;
    }

    function startPresale() public onlyOwner {
        require(currentState == State.CLOSED, "Presale already started");
        currentState = State.PRESALE;
        emit PresaleStarted();
    }

    function startPublicSale() public onlyOwner {
        require(currentState == State.PRESALE, "Public sale already started");
        currentState = State.PUBLIC;
        emit PublicSaleStarted();
    }

    function mint(uint256 numberOfTokens, bool isPresale) public payable noReentrancy {
        require(currentState == (isPresale ? State.PRESALE : State.PUBLIC), "Invalid state");
        require(msg.value >= price * numberOfTokens, "Insufficient payment");

        if (isPresale) {
            require(claimedWhitelistStatus[msg.sender], "Not whitelisted");
            claimedWhitelistStatus[msg.sender] = false;
        }

        require(totalSupply + numberOfTokens <= maxSupply, "Max supply reached");

        for (uint256 i = 0; i < numberOfTokens; i++) {
            _mint(msg.sender, totalSupply + i);
        }

        totalSupply += numberOfTokens;
        emit Minted(msg.sender, numberOfTokens);
    }

    function mintNFT(uint256 numberOfTokens) public payable {
        mint(numberOfTokens, true);
    }

    function mintPublicNFT(uint256 numberOfTokens) public payable {
        mint(numberOfTokens, false);
    }

    function _mint(address to, uint256 tokenId) internal virtual {
        // Implementation of the minting logic, e.g., ERC721 implementation
    }

    function getPrice() public view returns (uint256) {
        return price;
    }

    function getMaxSupply() public view returns (uint256) {
        return maxSupply;
    }

    function getClaimedWhitelistStatus(address user) public view returns (bool) {
        return claimedWhitelistStatus[user];
    }
}
